// >>> A MODIFIER : colle ta cle Google et liste tes departements <<<
const apiKey = "COLLE_TA_CLE_GOOGLE_ICI";
const departements = ["Dordogne", "Luberon", "Finistère"];

const modeles = ["gîte {d}", "location saisonnière {d}", "chambre d'hôtes {d}"];
const out = [];
for (const d of departements) {
  for (const m of modeles) {
    out.push({ json: { query: m.replace("{d}", d), departement: d, apiKey } });
  }
}
return out;

// Aplatit les resultats Google, garde ceux avec un site, deduplique par domaine
const seen = new Set();
const out = [];
for (const item of $input.all()) {
  const places = item.json.places || [];
  for (const p of places) {
    const site = p.websiteUri;
    if (!site) continue;
    let domain = "";
    try { domain = new URL(site).hostname.replace(/^www\./, "").toLowerCase(); }
    catch (e) { continue; }
    if (!domain || seen.has(domain)) continue;
    seen.add(domain);
    out.push({ json: {
      nom: (p.displayName && p.displayName.text) || "",
      adresse: p.formattedAddress || "",
      telephone: p.nationalPhoneNumber || "",
      site,
    }});
  }
}
return out;

// Visite chaque site et extrait le premier email de contact trouve
const EMAIL_RE = /[A-Za-z0-9._%+\-]+@[A-Za-z0-9.\-]+\.[A-Za-z]{2,}/g;
const BLOCK = ["example.com", "wixpress", "sentry", "godaddy", "jimdo",
  "squarespace", ".png", ".jpg", ".jpeg", ".gif", ".webp", ".svg", "@2x"];
const out = [];
for (const item of $input.all()) {
  const d = item.json;
  let html = "";
  try {
    const res = await this.helpers.httpRequest({
      url: d.site,
      method: "GET",
      timeout: 12000,
      headers: { "User-Agent": "Mozilla/5.0 (KordiaProspection)" },
    });
    html = typeof res === "string" ? res : JSON.stringify(res);
  } catch (e) {
    html = "";
  }
  const found = (html.match(EMAIL_RE) || [])
    .map((e) => e.toLowerCase().replace(/\.$/, ""))
    .filter((e) => !BLOCK.some((b) => e.includes(b)));
  out.push({ json: {
    nom: d.nom,
    email: found[0] || "",
    telephone: d.telephone,
    site: d.site,
    adresse: d.adresse,
  }});
  await new Promise((r) => setTimeout(r, 800));
}
return out;
